async (page) => {
  // Set attack style to Stab (index 0 = Accuracy+Defense for Iron Spear)
  await page.evaluate(() => window.game.menu.profile.attackStyleCallback(0));
  await page.waitForTimeout(500);

  // Attack Snek E1 at (239,136) click_x:600, click_y:96
  await page.evaluate(({x, y}) => {
    document.getElementById('canvas').dispatchEvent(new MouseEvent('click', { clientX: x, clientY: y, bubbles: true, ctrlKey: false }));
  }, { x: 600, y: 96 });
  await page.waitForTimeout(6000);

  // Check state after attack
  const state = await page.evaluate(() => {
    const s = window.__latestGameState;
    return {
      pos: s.player_position,
      hp: `${s.player_stats.hp}/${s.player_stats.max_hp}`,
      target: s.current_target,
      last_combat: s.last_combat,
      last_xp: s.last_xp_event,
      skills_acc: window.game.player.skills[1] ? `${window.game.player.skills[1].level}(${window.game.player.skills[1].experience}xp)` : 'N/A',
      skills_str: window.game.player.skills[6] ? `${window.game.player.skills[6].level}(${window.game.player.skills[6].experience}xp)` : 'N/A',
      chat: s.ui_state.recent_chat
    };
  });
  return JSON.stringify(state);
}
